package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.io.*;
import java.nio.file.*;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FileServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = Logger.getLogger(FileServiceImpl.class.getName());
    private static final String UPLOAD_DIR = "/tmp/grpc_uploads/";
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB chunks for download

    public FileServiceImpl() {
        try {
            Files.createDirectories(Paths.get(UPLOAD_DIR));
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Failed to create upload directory", e);
        }
    }

    @Override
    public StreamObserver<FileChunk> uploadFile(StreamObserver<UploadStatus> responseObserver) {
        return new StreamObserver<FileChunk>() {
            private String filename;
            private ByteArrayOutputStream buffer = new ByteArrayOutputStream();
            private long totalBytesReceived = 0;
            private MessageDigest digest;

            {
                try {
                    digest = MessageDigest.getInstance("SHA-256");
                } catch (NoSuchAlgorithmException e) {
                    logger.log(Level.SEVERE, "SHA-256 not available", e);
                }
            }

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (filename == null) {
                        filename = chunk.getFilename();
                        logger.info("Starting upload for file: " + filename + 
                                   ", total size: " + chunk.getTotalSize());
                    }

                    byte[] data = chunk.getContent().toByteArray();
                    buffer.write(data);
                    totalBytesReceived += data.length;

                    if (digest != null) {
                        digest.update(data);
                    }

                    logger.fine("Received chunk at offset " + chunk.getOffset() + 
                               ", size: " + data.length + 
                               ", total received: " + totalBytesReceived);

                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error processing chunk", e);
                    responseObserver.onError(
                        Status.INTERNAL
                            .withDescription("Error processing chunk: " + e.getMessage())
                            .asRuntimeException()
                    );
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.WARNING, "Upload error for file: " + filename, t);
                cleanup();
            }

            @Override
            public void onCompleted() {
                try {
                    Path filePath = Paths.get(UPLOAD_DIR, filename);
                    Files.write(filePath, buffer.toByteArray(), 
                               StandardOpenOption.CREATE, 
                               StandardOpenOption.TRUNCATE_EXISTING);

                    String checksum = bytesToHex(digest.digest());

                    logger.info("Upload completed for file: " + filename + 
                               ", bytes: " + totalBytesReceived +
                               ", checksum: " + checksum);

                    UploadStatus status = UploadStatus.newBuilder()
                            .setSuccess(true)
                            .setMessage("File uploaded successfully. Checksum: " + checksum)
                            .setBytesReceived(totalBytesReceived)
                            .build();

                    responseObserver.onNext(status);
                    responseObserver.onCompleted();

                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error writing file", e);
                    responseObserver.onError(
                        Status.INTERNAL
                            .withDescription("Failed to save file: " + e.getMessage())
                            .asRuntimeException()
                    );
                } finally {
                    cleanup();
                }
            }

            private void cleanup() {
                try {
                    buffer.close();
                } catch (IOException e) {
                    // ignore
                }
            }
        };
    }

    @Override
    public void downloadFile(FileRequest request, StreamObserver<FileChunk> responseObserver) {
        String filename = request.getFilename();
        Path filePath = Paths.get(UPLOAD_DIR, filename);

        if (!Files.exists(filePath)) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription("File not found: " + filename)
                    .asRuntimeException()
            );
            return;
        }

        try {
            long fileSize = Files.size(filePath);
            logger.info("Starting download for file: " + filename + ", size: " + fileSize);

            try (InputStream inputStream = new BufferedInputStream(
                    Files.newInputStream(filePath))) {
                
                byte[] chunkBuffer = new byte[CHUNK_SIZE];
                int bytesRead;
                long offset = 0;

                while ((bytesRead = inputStream.read(chunkBuffer)) != -1) {
                    FileChunk chunk = FileChunk.newBuilder()
                            .setFilename(filename)
                            .setContent(ByteString.copyFrom(chunkBuffer, 0, bytesRead))
                            .setOffset(offset)
                            .setTotalSize(fileSize)
                            .build();

                    responseObserver.onNext(chunk);
                    offset += bytesRead;
                }

                responseObserver.onCompleted();
                logger.info("Download completed for file: " + filename);

            }
        } catch (IOException e) {
            logger.log(Level.SEVERE, "Error reading file for download", e);
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Error reading file: " + e.getMessage())
                    .asRuntimeException()
            );
        }
    }

    private static String bytesToHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        return sb.toString();
    }
}

