package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;
import java.util.logging.Level;
import java.util.logging.Logger;

public class DataProcessingServiceImpl extends FileServiceGrpc.FileServiceImplBase {

    private static final Logger logger = Logger.getLogger(DataProcessingServiceImpl.class.getName());
    private final ConcurrentHashMap<String, AtomicLong> sessionCounters = new ConcurrentHashMap<>();

    @Override
    public StreamObserver<DataMessage> processData(StreamObserver<DataMessage> responseObserver) {
        String sessionId = UUID.randomUUID().toString();
        sessionCounters.put(sessionId, new AtomicLong(0));

        logger.info("New bidirectional processing session started: " + sessionId);

        return new StreamObserver<DataMessage>() {

            @Override
            public void onNext(DataMessage request) {
                try {
                    long messageCount = sessionCounters.get(sessionId).incrementAndGet();

                    logger.fine("Session " + sessionId + " - Processing message #" + messageCount +
                               ", id: " + request.getId() +
                               ", type: " + request.getType() +
                               ", payload size: " + request.getPayload().size());

                    switch (request.getType()) {
                        case REQUEST:
                            handleRequest(request, responseObserver, sessionId);
                            break;
                        case ACK:
                            handleAck(request, sessionId);
                            break;
                        default:
                            sendError(responseObserver, request.getId(),
                                    "Unsupported message type: " + request.getType());
                    }

                } catch (Exception e) {
                    logger.log(Level.SEVERE, "Error processing message in session " + sessionId, e);
                    sendError(responseObserver, request.getId(),
                            "Processing error: " + e.getMessage());
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.WARNING, "Session " + sessionId + " error", t);
                sessionCounters.remove(sessionId);
            }

            @Override
            public void onCompleted() {
                long totalProcessed = sessionCounters.getOrDefault(sessionId, new AtomicLong(0)).get();
                logger.info("Session " + sessionId + " completed. Total messages processed: " + totalProcessed);

                DataMessage summary = DataMessage.newBuilder()
                        .setId(UUID.randomUUID().toString())
                        .setType(MessageType.RESPONSE)
                        .setPayload(ByteString.copyFromUtf8(
                                "Session complete. Processed " + totalProcessed + " messages."))
                        .putMetadata("session_id", sessionId)
                        .putMetadata("total_processed", String.valueOf(totalProcessed))
                        .build();

                responseObserver.onNext(summary);
                responseObserver.onCompleted();
                sessionCounters.remove(sessionId);
            }
        };
    }

    private void handleRequest(DataMessage request, StreamObserver<DataMessage> responseObserver, String sessionId) {
        byte[] payloadBytes = request.getPayload().toByteArray();

        // Process the data - example: compute hash, transform, aggregate
        byte[] processedData = processPayload(payloadBytes);

        DataMessage response = DataMessage.newBuilder()
                .setId(UUID.randomUUID().toString())
                .setType(MessageType.RESPONSE)
                .setPayload(ByteString.copyFrom(processedData))
                .putMetadata("original_id", request.getId())
                .putMetadata("session_id", sessionId)
                .putMetadata("original_size", String.valueOf(payloadBytes.length))
                .putMetadata("processed_size", String.valueOf(processedData.length))
                .putAllMetadata(request.getMetadataMap())
                .build();

        responseObserver.onNext(response);
    }

    private void handleAck(DataMessage request, String sessionId) {
        logger.fine("ACK received in session " + sessionId + " for message: " + request.getId());
    }

    private void sendError(StreamObserver<DataMessage> responseObserver, String originalId, String errorMessage) {
        DataMessage errorResponse = DataMessage.newBuilder()
                .setId(UUID.randomUUID().toString())
                .setType(MessageType.ERROR)
                .setPayload(ByteString.copyFromUtf8(errorMessage))
                .putMetadata("original_id", originalId)
                .build();

        responseObserver.onNext(errorResponse);
    }

    private byte[] processPayload(byte[] data) {
        try {
            // Example processing: compute SHA-256 hash + return transformed data
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(data);

            // Combine hash + original data as "processed" output
            byte[] result = new byte[hash.length + data.length];
            System.arraycopy(hash, 0, result, 0, hash.length);
            System.arraycopy(data, 0, result, hash.length, data.length);

            return result;
        } catch (Exception e) {
            logger.log(Level.WARNING, "Error processing payload", e);
            return data;
        }
    }
}

