package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.io.*;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class FileServiceClient {

    private static final Logger logger = Logger.getLogger(FileServiceClient.class.getName());
    private static final int CHUNK_SIZE = 1024 * 1024; // 1MB chunks
    private static final int MAX_MESSAGE_SIZE = Integer.MAX_VALUE;

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceStub asyncStub;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;

    public FileServiceClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(MAX_MESSAGE_SIZE)
                .keepAliveTime(5, TimeUnit.MINUTES)
                .keepAliveTimeout(20, TimeUnit.SECONDS)
                .build();

        asyncStub = FileServiceGrpc.newStub(channel);
        blockingStub = FileServiceGrpc.newBlockingStub(channel);
    }

    public void uploadFile(String filePath) throws InterruptedException, IOException {
        Path path = Paths.get(filePath);
        String filename = path.getFileName().toString();
        long fileSize = Files.size(path);

        logger.info("Uploading file: " + filename + ", size: " + fileSize);

        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                logger.info("Upload status - Success: " + status.getSuccess() +
                           ", Message: " + status.getMessage() +
                           ", Bytes received: " + status.getBytesReceived());
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Upload failed", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed.");
                latch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        try (InputStream inputStream = new BufferedInputStream(Files.newInputStream(path))) {
            byte[] buffer = new byte[CHUNK_SIZE];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                        .setFilename(filename)
                        .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                        .setOffset(offset)
                        .setTotalSize(fileSize)
                        .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                // Flow control: check if the stream is ready
                Thread.sleep(1); // minimal backpressure
            }
        }

        requestObserver.onCompleted();
        latch.await(5, TimeUnit.MINUTES);
    }

    public void downloadFile(String filename, String outputPath) throws InterruptedException {
        logger.info("Downloading file: " + filename);

        CountDownLatch latch = new CountDownLatch(1);
        FileRequest request = FileRequest.newBuilder()
                .setFilename(filename)
                .build();

        asyncStub.downloadFile(request, new StreamObserver<FileChunk>() {
            private ByteArrayOutputStream buffer = new ByteArrayOutputStream();

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    byte[] data = chunk.getContent().toByteArray();
                    buffer.write(data);
                    logger.fine("Downloaded chunk at offset " + chunk.getOffset() +
                               ", size: " + data.length);
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error writing download chunk", e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Download failed", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                try {
                    Files.write(Paths.get(outputPath), buffer.toByteArray());
                    logger.info("Download completed. File saved to: " + outputPath);
                } catch (IOException e) {
                    logger.log(Level.SEVERE, "Error saving downloaded file", e);
                } finally {
                    latch.countDown();
                }
            }
        });

        latch.await(5, TimeUnit.MINUTES);
    }

    public void processDataBidirectional(int messageCount) throws InterruptedException {
        logger.info("Starting bidirectional data processing with " + messageCount + " messages");

        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<DataMessage> responseObserver = new StreamObserver<DataMessage>() {
            private int responsesReceived = 0;

            @Override
            public void onNext(DataMessage response) {
                responsesReceived++;
                logger.info("Received response #" + responsesReceived +
                           ", id: " + response.getId() +
                           ", type: " + response.getType() +
                           ", payload size: " + response.getPayload().size() +
                           ", metadata: " + response.getMetadataMap());
            }

            @Override
            public void onError(Throwable t) {
                logger.log(Level.SEVERE, "Bidirectional stream error", t);
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed. Total responses: " + responsesReceived);
                latch.countDown();
            }
        };

        StreamObserver<DataMessage> requestObserver = asyncStub.processData(responseObserver);

        try {
            for (int i = 0; i < messageCount; i++) {
                String payload = "Data payload #" + i + " - " + UUID.randomUUID().toString();

                DataMessage message = DataMessage.newBuilder()
                        .setId(UUID.randomUUID().toString())
                        .setType(MessageType.REQUEST)
                        .setPayload(ByteString.copyFromUtf8(payload))
                        .putMetadata("sequence", String.valueOf(i))
                        .putMetadata("timestamp", String.valueOf(System.currentTimeMillis()))
                        .build();

                requestObserver.onNext(message);
                logger.fine("Sent message #" + i);

                // Simulate some processing delay
                Thread.sleep(100);
            }

            // Send ACK message
            DataMessage ack = DataMessage.newBuilder()
                    .setId(UUID.randomUUID().toString())
                    .setType(MessageType.ACK)
                    .setPayload(ByteString.copyFromUtf8("All messages sent"))
                    .build();
            requestObserver.onNext(ack);

        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        requestObserver.onCompleted();
        latch.await(5, TimeUnit.MINUTES);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(10, TimeUnit.SECONDS);
    }

    public static void main(String[] args) throws Exception {
        FileServiceClient client = new FileServiceClient("localhost", 50051);

        try {
            // Example: Upload a file
            if (args.length > 0 && "upload".equals(args[0])) {
                String filePath = args.length > 1 ? args[1] : "/tmp/test_upload.dat";
                client.uploadFile(filePath);
            }

            // Example: Download a file
            if (args.length > 0 && "download".equals(args[0])) {
                String filename = args.length > 1 ? args[1] : "test_upload.dat";
                String outputPath = args.length > 2 ? args[2] : "/tmp/downloaded_file.dat";
                client.downloadFile(filename, outputPath);
            }

            // Example: Bidirectional processing
            if (args.length > 0 && "process".equals(args[0])) {
                int count = args.length > 1 ? Integer.parseInt(args[1]) : 10;
                client.processDataBidirectional(count);
            }

            // Default: run all demos
            if (args.length == 0) {
                // Create a test file
                Path testFile = Paths.get("/tmp/test_upload.dat");
                byte[] testData = new byte[5 * 1024 * 1024]; // 5MB
                new java.util.Random().nextBytes(testData);
                Files.write(testFile, testData);

                // Upload
                client.uploadFile(testFile.toString());

                // Download
                client.downloadFile("test_upload.dat", "/tmp/downloaded_test.dat");

                // Bidirectional
                client.processDataBidirectional(5);
            }

        } finally {
            client.shutdown();
        }
    }
}

