package com.dataprocessing.grpc;

import io.grpc.*;

import java.util.logging.Level;
import java.util.logging.Logger;

public class GrpcServerInterceptor implements ServerInterceptor {

    private static final Logger logger = Logger.getLogger(GrpcServerInterceptor.class.getName());

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String methodName = call.getMethodDescriptor().getFullMethodName();
        long startTime = System.currentTimeMillis();

        logger.info("gRPC call started: " + methodName);

        // Log metadata
        logger.fine("Request metadata: " + headers.toString());

        ServerCall<ReqT, RespT> wrappedCall = new ForwardingServerCall.SimpleForwardingServerCall<ReqT, RespT>(call) {
            @Override
            public void close(Status status, Metadata trailers) {
                long duration = System.currentTimeMillis() - startTime;
                logger.info("gRPC call completed: " + methodName +
                           ", status: " + status.getCode() +
                           ", duration: " + duration + "ms");

                if (!status.isOk()) {
                    logger.log(Level.WARNING, "gRPC call failed: " + methodName +
                              ", status: " + status.getCode() +
                              ", description: " + status.getDescription());
                }

                super.close(status, trailers);
            }

            @Override
            public void sendMessage(RespT message) {
                logger.fine("Sending response message for: " + methodName);
                super.sendMessage(message);
            }
        };

        ServerCall.Listener<ReqT> listener = next.startCall(wrappedCall, headers);

        return new ForwardingServerCallListener.SimpleForwardingServerCallListener<ReqT>(listener) {
            @Override
            public void onMessage(ReqT message) {
                logger.fine("Received request message for: " + methodName);
                super.onMessage(message);
            }

            @Override
            public void onHalfClose() {
                try {
                    super.onHalfClose();
                } catch (RuntimeException e) {
                    logger.log(Level.SEVERE, "Error in onHalfClose for: " + methodName, e);
                    call.close(Status.INTERNAL.withDescription(e.getMessage()), new Metadata());
                }
            }

            @Override
            public void onCancel() {
                logger.info("gRPC call cancelled: " + methodName);
                super.onCancel();
            }

            @Override
            public void onComplete() {
                logger.fine("Client completed sending for: " + methodName);
                super.onComplete();
            }
        };
    }
}

